func solve(weight []int64) int64 {
    n := len(weight)
    if n < 2 {
        return 0
    }

    var count int64
    i := 0

    for i < n {
        maxVal := weight[i]
        j := i
        // Find the largest possible segment starting at i
        for j < n {
            if weight[j] > maxVal {
                maxVal = weight[j]
            }
            if j > i && weight[j] < maxVal {
                // Potential end of a balanced shipment
                // Check if we can extend further
                k := j + 1
                tempMax := maxVal
                for k < n {
                    if weight[k] > tempMax {
                        tempMax = weight[k]
                    }
                    if weight[k] < tempMax {
                        j = k
                        maxVal = tempMax
                    } else {
                        break
                    }
                    k++
                }
                count++
                i = j + 1
                break
            }
            j++
        }
        if j >= n {
            break
        }
    }

    return count
}
